package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVFormat.Predefined;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testValueOf_withValidFormat() throws Exception {
        // Using reflection to mock Predefined.valueOf since Mockito.mockStatic is not available
        Predefined predefined = Mockito.mock(Predefined.class);
        CSVFormat predefinedFormat = CSVFormat.DEFAULT;
        CSVFormat predefinedReturnedFormat = predefinedFormat.withAllowMissingColumnNames();
        Mockito.when(predefined.getFormat()).thenReturn(predefinedReturnedFormat);

        // Replace Predefined.valueOf with a proxy using reflection
        Method valueOfMethod = Predefined.class.getDeclaredMethod("valueOf", String.class);
        valueOfMethod.setAccessible(true);

        // Save original method reference to restore later if needed (not possible directly, so we skip)
        // Instead, we test CSVFormat.valueOf indirectly by mocking Predefined.valueOf via a spy on Predefined enum class

        // Because Predefined.valueOf is static final method generated by enum, we cannot mock it directly without mockStatic.
        // So we test CSVFormat.valueOf by spying on CSVFormat.Predefined enum constants.

        // Workaround: test CSVFormat.valueOf returns expected value by calling actual enum constant
        CSVFormat result = CSVFormat.valueOf("DEFAULT");
        assertNotNull(result);
        assertEquals(predefinedReturnedFormat, result.withAllowMissingColumnNames());

        // Since we cannot verify static call without mockStatic, we verify the returned value matches expected
    }

    @Test
    public void testValueOf_withDifferentFormat() throws Exception {
        CSVFormat predefinedReturnedFormat = CSVFormat.EXCEL;

        // Similar approach: test actual CSVFormat.valueOf returns expected format
        CSVFormat result = CSVFormat.valueOf("EXCEL");
        assertNotNull(result);
        assertEquals(predefinedReturnedFormat, result);

        // No static mocking, so no verification of static method call
    }

    @Test
    public void testValueOf_reflection_invocation() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("valueOf", String.class);
        method.setAccessible(true);

        Object result = method.invoke(null, "RFC4180");
        assertNotNull(result);
        assertTrue(result instanceof CSVFormat);
        assertEquals(CSVFormat.RFC4180, result);
    }
}
